import matplotlib; matplotlib.use("Agg"); import matplotlib.pyplot as plt; import numpy as np; fig, ax = plt.subplots(figsize=(5, 5)); ax.set_aspect('equal'); ax.set_xlim(-6, 6); ax.set_ylim(-6, 6); ax.axis('off'); ax.annotate('', xy=(5.5, 0), xytext=(-5.5, 0), arrowprops=dict(arrowstyle='<->', color='#1a1a1a', lw=1)); ax.annotate('', xy=(0, 5.5), xytext=(0, -5.5), arrowprops=dict(arrowstyle='<->', color='#1a1a1a', lw=1)); ax.text(5.6, -0.4, 'x', fontsize=12); ax.text(-0.4, 5.6, 'y', fontsize=12); x = np.linspace(-4.5, 4.5, 100); ax.plot(x, 0.6*x + 1.5, color='#1a1a1a', lw=2); ax.plot(x, 0.6*x - 1.5, color='#1a1a1a', lw=2); plt.savefig('out.png', dpi=150)